export * from "./scheduler-kit-adapter";
export * from "./scheduler-kit-state";
export * from "./scheduler-kit";

export interface SchedulerCalendar {
  /** Stable unique calendar identifier referenced by events and visibility filters. */
  readonly id: string;
  /** Human-readable calendar name shown in filtering controls. */
  readonly label: string;
}

export interface SchedulerEvent {
  /** Identifier of the calendar that owns this event. */
  readonly calendarId: string;
  /** Optional plain-text event detail supplied by the scheduling service. */
  readonly description?: string;
  /** Absolute ISO-compatible end instant interpreted in the selected display timezone. */
  readonly end: string;
  /** Stable event identifier used for editing, removal, and conflict relationships. */
  readonly id: string;
  /** Optional human-readable event location. */
  readonly location?: string;
  /** Absolute ISO-compatible start instant interpreted in the selected display timezone. */
  readonly start: string;
  /** Concise event title rendered in agenda and calendar presentations. */
  readonly title: string;
}

export interface SchedulerConflict {
  /** Identifier of the event whose save produced or owns the conflict. */
  readonly eventId: string;
  /** Stable conflict identifier passed to resolution operations. */
  readonly id: string;
  /** Existing event identifiers related to the conflict. */
  readonly relatedEventIds: readonly string[];
  /** Human-readable overlap or constraint explanation shown in recovery guidance. */
  readonly summary: string;
}

export interface SchedulerSnapshot {
  /** Immutable calendars available for event ownership and filtering. */
  readonly calendars: readonly SchedulerCalendar[];
  /** Immutable unresolved conflict records supplied by the adapter. */
  readonly conflicts: readonly SchedulerConflict[];
  /** Immutable event collection supplied by the adapter. */
  readonly events: readonly SchedulerEvent[];
}

export interface SchedulerEventInput {
  /** Target calendar identifier for the event being saved. */
  readonly calendarId: string;
  /** Local calendar date in `YYYY-MM-DD` form. */
  readonly date: string;
  /** Optional plain-text description for the event. */
  readonly description?: string;
  /** Local exclusive end time in 24-hour `HH:mm` form. */
  readonly endTime: string;
  /** Existing event identifier for updates; omission requests creation. */
  readonly id?: string;
  /** Optional human-readable event location. */
  readonly location?: string;
  /** Local start time in 24-hour `HH:mm` form. */
  readonly startTime: string;
  /** IANA timezone identifier defining how local date and time values should be resolved. */
  readonly timeZone: string;
  /** Required concise title for the event. */
  readonly title: string;
}

export interface SchedulerSaveResult {
  /** Conflicts detected for the saved event, empty when no recovery is required. */
  readonly conflicts: readonly SchedulerConflict[];
  /** Canonical event record returned after the adapter saves the request. */
  readonly event: SchedulerEvent;
}

export interface SchedulerAdapter {
  /** Loads the latest immutable schedule snapshot with lifecycle cancellation. */
  readonly load: (signal: AbortSignal) => Promise<SchedulerSnapshot>;
  /** Optionally removes one event; omission cleanly disables removal actions. */
  readonly remove?: (eventId: string, signal: AbortSignal) => Promise<void>;
  /** Optionally resolves one conflict; omission cleanly disables conflict resolution actions. */
  readonly resolveConflict?: (
    conflictId: string,
    resolution: "keep-existing" | "save-anyway",
    signal: AbortSignal,
  ) => Promise<void>;
  /** Creates or updates an event and returns its canonical record and conflicts. */
  readonly save: (input: SchedulerEventInput, signal: AbortSignal) => Promise<SchedulerSaveResult>;
}

const FIXTURE_EPOCH_DATE = "1970-01-01";

export function createDeterministicSchedulerSnapshot(): SchedulerSnapshot {
  return {
    calendars: [
      { id: "shared", label: "Shared calendar" },
      { id: "focus", label: "Focus calendar" },
    ],
    conflicts: [
      {
        eventId: "review",
        id: "review-overlap",
        relatedEventIds: ["focus-block"],
        summary: "Review overlaps Focus block by 30 minutes.",
      },
    ],
    events: [
      {
        calendarId: "shared",
        end: `${FIXTURE_EPOCH_DATE}T10:30:00.000Z`,
        id: "review",
        location: "Room One",
        start: `${FIXTURE_EPOCH_DATE}T09:30:00.000Z`,
        title: "Interface review",
      },
      {
        calendarId: "focus",
        end: `${FIXTURE_EPOCH_DATE}T11:30:00.000Z`,
        id: "focus-block",
        start: `${FIXTURE_EPOCH_DATE}T10:00:00.000Z`,
        title: "Focus block",
      },
    ],
  };
}

function ensureActive(signal: AbortSignal): void {
  if (signal.aborted) throw new DOMException("The operation was aborted.", "AbortError");
}

function validateInput(input: SchedulerEventInput): void {
  if (input.title.trim().length === 0 || input.title.length > 160) {
    throw new Error("Use an event title from 1 to 160 characters.");
  }
  if (!/^\d{4}-\d{2}-\d{2}$/u.test(input.date)) {
    throw new Error("Choose a valid event date.");
  }
  if (!/^\d{2}:\d{2}$/u.test(input.startTime) || !/^\d{2}:\d{2}$/u.test(input.endTime)) {
    throw new Error("Choose valid start and end times.");
  }
  if (input.endTime <= input.startTime) {
    throw new Error("End time must be later than start time.");
  }
}

export function createDeterministicSchedulerAdapter(): SchedulerAdapter {
  let snapshot = createDeterministicSchedulerSnapshot();
  return {
    async load(signal) {
      ensureActive(signal);
      return snapshot;
    },
    async remove(eventId, signal) {
      ensureActive(signal);
      snapshot = {
        ...snapshot,
        conflicts: snapshot.conflicts.filter((conflict) => conflict.eventId !== eventId),
        events: snapshot.events.filter((event) => event.id !== eventId),
      };
    },
    async resolveConflict(conflictId, resolution, signal) {
      ensureActive(signal);
      if (resolution === "keep-existing") {
        const conflict = snapshot.conflicts.find((candidate) => candidate.id === conflictId);
        if (conflict !== undefined) {
          snapshot = {
            ...snapshot,
            events: snapshot.events.filter((event) => event.id !== conflict.eventId),
          };
        }
      }
      snapshot = {
        ...snapshot,
        conflicts: snapshot.conflicts.filter((conflict) => conflict.id !== conflictId),
      };
    },
    async save(input, signal) {
      ensureActive(signal);
      validateInput(input);
      if (input.timeZone !== "UTC") {
        throw new Error(
          "The deterministic adapter accepts UTC only; production adapters must resolve local wall time.",
        );
      }
      const id = input.id ?? `event-${input.date}-${input.startTime.replace(":", "")}`;
      const event: SchedulerEvent = {
        calendarId: input.calendarId,
        ...(input.description === undefined ? {} : { description: input.description }),
        end: `${input.date}T${input.endTime}:00.000Z`,
        id,
        ...(input.location === undefined ? {} : { location: input.location }),
        start: `${input.date}T${input.startTime}:00.000Z`,
        title: input.title.trim(),
      };
      const overlaps = snapshot.events.filter(
        (candidate) =>
          candidate.id !== event.id && candidate.start < event.end && candidate.end > event.start,
      );
      const conflicts = overlaps.map((candidate) => ({
        eventId: event.id,
        id: `${event.id}-overlap-${candidate.id}`,
        relatedEventIds: [candidate.id],
        summary: `${event.title} overlaps ${candidate.title}.`,
      }));
      snapshot = {
        ...snapshot,
        conflicts: [
          ...snapshot.conflicts.filter((conflict) => conflict.eventId !== event.id),
          ...conflicts,
        ],
        events: [...snapshot.events.filter((candidate) => candidate.id !== event.id), event],
      };
      return { conflicts, event };
    },
  };
}

"use client";

import { useCallback, useEffect, useRef, useState } from "react";

import type {
  SchedulerAdapter,
  SchedulerEventInput,
  SchedulerSnapshot,
} from "./scheduler-kit-adapter";

export type SchedulerLoadState = "empty" | "error" | "loading" | "offline" | "ready";
export type SchedulerMutationState = "error" | "idle" | "pending" | "success";

export interface UseSchedulerOptions {
  /** Consumer scheduling adapter used for cancellable loading and mutations. */
  readonly adapter: SchedulerAdapter;
  /** Optional server-provided snapshot that avoids the initial client load request. */
  readonly initialSnapshot?: SchedulerSnapshot;
  /** Prevents adapter requests and exposes the explicit offline state when true. */
  readonly offline?: boolean;
}

export function useScheduler({ adapter, initialSnapshot, offline = false }: UseSchedulerOptions) {
  const [snapshot, setSnapshot] = useState<SchedulerSnapshot | null>(initialSnapshot ?? null);
  const [state, setState] = useState<SchedulerLoadState>(
    offline
      ? "offline"
      : initialSnapshot === undefined
        ? "loading"
        : initialSnapshot.events.length === 0
          ? "empty"
          : "ready",
  );
  const [error, setError] = useState("");
  const [mutationState, setMutationState] = useState<SchedulerMutationState>("idle");
  const [mutationError, setMutationError] = useState("");
  const activeRequest = useRef<AbortController | null>(null);

  const reload = useCallback(async () => {
    if (offline) {
      setState("offline");
      return;
    }
    activeRequest.current?.abort();
    const controller = new AbortController();
    activeRequest.current = controller;
    setState("loading");
    try {
      const next = await adapter.load(controller.signal);
      if (controller.signal.aborted) return;
      setSnapshot(next);
      setState(next.events.length === 0 ? "empty" : "ready");
      setError("");
    } catch (loadError) {
      if (controller.signal.aborted) return;
      setError(loadError instanceof Error ? loadError.message : "The schedule could not load.");
      setState("error");
    }
  }, [adapter, offline]);

  useEffect(() => {
    if (initialSnapshot === undefined) void reload();
    return () => activeRequest.current?.abort();
  }, [initialSnapshot, reload]);

  const mutate = async (action: (signal: AbortSignal) => Promise<void>): Promise<boolean> => {
    if (offline || snapshot === null) return false;
    activeRequest.current?.abort();
    const controller = new AbortController();
    activeRequest.current = controller;
    setMutationState("pending");
    setMutationError("");
    try {
      await action(controller.signal);
      if (controller.signal.aborted) return false;
      const next = await adapter.load(controller.signal);
      if (controller.signal.aborted) return false;
      setSnapshot(next);
      setMutationState("success");
      setState(next.events.length === 0 ? "empty" : "ready");
      return true;
    } catch (mutationFailure) {
      if (controller.signal.aborted) return false;
      setMutationError(
        mutationFailure instanceof Error
          ? mutationFailure.message
          : "The schedule change could not be completed.",
      );
      setMutationState("error");
      return false;
    }
  };

  const save = (input: SchedulerEventInput) =>
    mutate((signal) => adapter.save(input, signal).then(() => undefined));
  const remove = (eventId: string) =>
    adapter.remove === undefined
      ? Promise.resolve(false)
      : mutate((signal) => adapter.remove!(eventId, signal));
  const resolveConflict = (conflictId: string, resolution: "keep-existing" | "save-anyway") =>
    adapter.resolveConflict === undefined
      ? Promise.resolve(false)
      : mutate((signal) => adapter.resolveConflict!(conflictId, resolution, signal));

  return {
    error,
    mutationError,
    mutationState,
    reload,
    remove,
    resolveConflict,
    save,
    snapshot,
    state,
  } as const;
}

@layer mergora.components {
  .mrg-scheduler-kit {
    display: grid;
    grid-template-columns: minmax(12rem, 17rem) minmax(0, 1fr);
    max-inline-size: var(--mrg-semantic-size-content-wide);
    overflow: clip;
    border: var(--mrg-semantic-border-width-default) solid var(--mrg-semantic-color-border-strong);
    border-radius: var(--mrg-semantic-radius-panel);
    color: var(--mrg-semantic-color-foreground-primary);
    background: var(--mrg-semantic-color-background-canvas);
    font-family: var(--mrg-semantic-font-family-prose);
  }

  .mrg-scheduler-kit h1,
  .mrg-scheduler-kit h2,
  .mrg-scheduler-kit h3,
  .mrg-scheduler-kit p {
    margin-block: 0;
  }

  .mrg-scheduler-kit [data-slot="scheduler-header"] {
    grid-column: 1 / -1;
    display: flex;
    align-items: start;
    justify-content: space-between;
    gap: var(--mrg-semantic-space-stack-md);
    padding: var(--mrg-semantic-density-panel-padding);
    border-block-end: var(--mrg-semantic-border-width-emphasis) solid
      var(--mrg-semantic-color-brand-action);
  }

  .mrg-scheduler-kit h1 {
    font-size: var(--mrg-semantic-font-size-heading-medium);
    line-height: var(--mrg-semantic-font-line-height-heading);
    text-wrap: balance;
  }

  .mrg-scheduler-kit h2 {
    font-size: var(--mrg-semantic-font-size-heading-small);
    line-height: var(--mrg-semantic-font-line-height-heading);
  }

  .mrg-scheduler-kit [data-slot="scheduler-header"] p,
  .mrg-scheduler-kit [data-slot="scheduler-section-heading"] p,
  .mrg-scheduler-kit [data-slot="scheduler-agenda"] li button span span {
    color: var(--mrg-semantic-color-foreground-muted);
    font-size: var(--mrg-semantic-font-size-caption);
  }

  .mrg-scheduler-kit [data-slot="scheduler-maturity"] {
    display: inline-block;
    margin-block-end: var(--mrg-semantic-space-stack-xs);
    color: var(--mrg-semantic-color-accent-foreground);
    font-size: var(--mrg-semantic-font-size-label);
    font-weight: var(--mrg-semantic-font-weight-label);
  }

  .mrg-scheduler-kit [data-slot="scheduler-view"],
  .mrg-scheduler-kit [data-slot="scheduler-actions"] {
    display: flex;
    flex-wrap: wrap;
    gap: var(--mrg-semantic-space-inline-xs);
  }

  .mrg-scheduler-kit [data-slot="scheduler-filters"] {
    display: grid;
    align-content: start;
    gap: var(--mrg-semantic-space-stack-md);
    padding: var(--mrg-semantic-density-panel-padding);
    border-inline-end: var(--mrg-semantic-border-width-default) solid
      var(--mrg-semantic-color-border-default);
    background: var(--mrg-semantic-color-background-surface);
  }

  .mrg-scheduler-kit fieldset {
    display: grid;
    gap: var(--mrg-semantic-space-stack-xs);
    padding: 0;
    border: 0;
    margin: 0;
  }

  .mrg-scheduler-kit legend,
  .mrg-scheduler-kit label {
    font-size: var(--mrg-semantic-font-size-label);
    font-weight: var(--mrg-semantic-font-weight-label);
  }

  .mrg-scheduler-kit fieldset label {
    display: flex;
    align-items: center;
    gap: var(--mrg-semantic-space-inline-xs);
    min-block-size: var(--mrg-semantic-size-target-minimum);
  }

  .mrg-scheduler-kit [data-slot="scheduler-calendar-mark"],
  .mrg-scheduler-kit [data-slot="scheduler-event-mark"] {
    inline-size: var(--mrg-semantic-size-icon-sm);
    block-size: var(--mrg-semantic-size-icon-sm);
    flex: none;
    border: var(--mrg-semantic-border-width-default) solid
      var(--mrg-semantic-color-selection-border);
    border-radius: var(--mrg-semantic-radius-compact);
    background: var(--mrg-semantic-color-brand-living);
  }

  .mrg-scheduler-kit [data-slot="scheduler-main"] {
    display: grid;
    grid-template-columns: minmax(18rem, 0.9fr) minmax(18rem, 1.1fr);
    min-inline-size: 0;
  }

  .mrg-scheduler-kit
    [data-slot="scheduler-main"][data-view="agenda"]
    [data-slot="scheduler-calendar-panel"] {
    display: none;
  }

  .mrg-scheduler-kit [data-slot="scheduler-main"][data-view="agenda"] {
    grid-template-columns: minmax(0, 1fr);
  }

  .mrg-scheduler-kit [data-slot="scheduler-calendar-panel"],
  .mrg-scheduler-kit [data-slot="scheduler-agenda"],
  .mrg-scheduler-kit [data-slot="scheduler-editor"],
  .mrg-scheduler-kit [data-slot="scheduler-conflicts"] {
    min-inline-size: 0;
    padding: var(--mrg-semantic-density-panel-padding);
    border-block-end: var(--mrg-semantic-border-width-default) solid
      var(--mrg-semantic-color-border-default);
  }

  .mrg-scheduler-kit [data-slot="scheduler-calendar-panel"] {
    border-inline-end: var(--mrg-semantic-border-width-default) solid
      var(--mrg-semantic-color-border-default);
  }

  .mrg-scheduler-kit [data-slot="scheduler-editor"],
  .mrg-scheduler-kit [data-slot="scheduler-conflicts"] {
    grid-column: 1 / -1;
  }

  .mrg-scheduler-kit [data-slot="scheduler-section-heading"] {
    display: flex;
    align-items: start;
    justify-content: space-between;
    gap: var(--mrg-semantic-space-inline-sm);
    margin-block-end: var(--mrg-semantic-space-stack-md);
  }

  .mrg-scheduler-kit [data-slot="scheduler-agenda"] ol {
    display: grid;
    gap: var(--mrg-semantic-space-stack-xs);
    padding: 0;
    margin: 0;
    list-style: none;
  }

  .mrg-scheduler-kit [data-slot="scheduler-agenda"] li button {
    display: flex;
    align-items: start;
    gap: var(--mrg-semantic-space-inline-sm);
    inline-size: 100%;
    min-block-size: var(--mrg-semantic-size-target-preferred);
    padding: var(--mrg-semantic-space-inset-sm);
    border: var(--mrg-semantic-border-width-default) solid var(--mrg-semantic-color-border-default);
    border-radius: var(--mrg-semantic-radius-control);
    color: inherit;
    background: var(--mrg-semantic-color-background-canvas);
    font: inherit;
    text-align: start;
  }

  .mrg-scheduler-kit [data-slot="scheduler-agenda"] li button > span:last-child {
    display: grid;
    gap: var(--mrg-semantic-space-stack-xs);
  }

  .mrg-scheduler-kit [data-slot="scheduler-agenda"] li button[aria-pressed="true"] {
    border-color: var(--mrg-semantic-color-selection-border);
    color: var(--mrg-semantic-color-selection-foreground);
    background: var(--mrg-semantic-color-selection-background);
  }

  .mrg-scheduler-kit form {
    display: grid;
    grid-template-columns: minmax(8rem, 0.3fr) minmax(0, 1fr);
    gap: var(--mrg-semantic-space-stack-sm) var(--mrg-semantic-space-inline-md);
    max-inline-size: 48rem;
    margin-block-start: var(--mrg-semantic-space-stack-md);
  }

  .mrg-scheduler-kit form > :not(label) {
    min-inline-size: 0;
  }

  .mrg-scheduler-kit :is(input, select, textarea) {
    min-block-size: var(--mrg-semantic-density-control-height);
    padding: var(--mrg-semantic-density-control-padding-block)
      var(--mrg-semantic-density-control-padding-inline);
    border: var(--mrg-semantic-border-width-default) solid
      var(--mrg-semantic-color-border-interactive);
    border-radius: var(--mrg-semantic-radius-control);
    color: var(--mrg-semantic-color-foreground-primary);
    background: var(--mrg-semantic-color-background-canvas);
    font: inherit;
  }

  .mrg-scheduler-kit [data-slot="scheduler-time-fields"] {
    display: flex;
    flex-wrap: wrap;
    gap: var(--mrg-semantic-space-inline-sm);
  }

  .mrg-scheduler-kit [data-slot="scheduler-time-fields"] label {
    display: grid;
    gap: var(--mrg-semantic-space-stack-xs);
  }

  .mrg-scheduler-kit [data-slot="scheduler-duration"],
  .mrg-scheduler-kit [data-slot="scheduler-timezone-context"],
  .mrg-scheduler-kit [data-slot="scheduler-conflicts"] article {
    padding: var(--mrg-semantic-space-inset-sm);
    border: var(--mrg-semantic-border-width-default) solid var(--mrg-semantic-color-accent-border);
    border-radius: var(--mrg-semantic-radius-compact);
    color: var(--mrg-semantic-color-accent-foreground-on-subtle);
    background: var(--mrg-semantic-color-accent-background-subtle);
  }

  .mrg-scheduler-kit [data-slot="scheduler-conflicts"] article + article {
    margin-block-start: var(--mrg-semantic-space-stack-sm);
  }

  .mrg-scheduler-kit [data-slot="scheduler-offline"],
  .mrg-scheduler-kit [data-slot="scheduler-error"] {
    grid-column: 1 / -1;
    padding: var(--mrg-semantic-space-inset-sm) var(--mrg-semantic-density-panel-padding);
    border-block-end: var(--mrg-semantic-border-width-default) solid
      var(--mrg-semantic-color-status-warning-border);
    color: var(--mrg-semantic-color-status-warning-foreground);
    background: var(--mrg-semantic-color-status-warning-background);
  }

  .mrg-scheduler-kit :is(button, input, select, textarea):focus-visible {
    box-shadow: 0 0 0 var(--mrg-semantic-focus-width)
      var(--mrg-semantic-color-focus-contrast-background);
    outline: var(--mrg-semantic-focus-width) solid var(--mrg-semantic-color-focus-ring);
    outline-offset: var(--mrg-semantic-focus-offset);
  }

  .mrg-scheduler-kit [data-slot="scheduler-announcer"] {
    position: absolute;
    inline-size: 1px;
    block-size: 1px;
    overflow: hidden;
    clip-path: inset(50%);
    white-space: nowrap;
  }

  @media (max-width: 58rem) {
    .mrg-scheduler-kit {
      grid-template-columns: minmax(0, 1fr);
    }

    .mrg-scheduler-kit [data-slot="scheduler-filters"] {
      border-inline-end: 0;
      border-block-end: var(--mrg-semantic-border-width-default) solid
        var(--mrg-semantic-color-border-default);
    }

    .mrg-scheduler-kit [data-slot="scheduler-main"] {
      grid-template-columns: minmax(0, 1fr);
    }

    .mrg-scheduler-kit [data-slot="scheduler-calendar-panel"] {
      display: none;
      border-inline-end: 0;
    }

    .mrg-scheduler-kit [data-slot="scheduler-agenda"]::before {
      content: "Responsive agenda view";
      display: block;
      margin-block-end: var(--mrg-semantic-space-stack-sm);
      color: var(--mrg-semantic-color-accent-foreground);
      font-size: var(--mrg-semantic-font-size-label);
      font-weight: var(--mrg-semantic-font-weight-label);
    }
  }

  @media (max-width: 32rem) {
    .mrg-scheduler-kit [data-slot="scheduler-header"],
    .mrg-scheduler-kit [data-slot="scheduler-section-heading"] {
      flex-direction: column;
    }

    .mrg-scheduler-kit form {
      grid-template-columns: minmax(0, 1fr);
    }
  }

  @media (prefers-reduced-motion: reduce) {
    .mrg-scheduler-kit *,
    .mrg-scheduler-kit *::before,
    .mrg-scheduler-kit *::after {
      scroll-behavior: auto;
      transition-duration: var(--mrg-semantic-motion-duration-reduced);
      animation-duration: var(--mrg-semantic-motion-duration-reduced);
    }
  }

  @media (forced-colors: active) {
    .mrg-scheduler-kit,
    .mrg-scheduler-kit [data-slot="scheduler-agenda"] li button,
    .mrg-scheduler-kit :is(input, select, textarea) {
      border-color: CanvasText;
      color: CanvasText;
      background: Canvas;
      forced-color-adjust: auto;
    }

    .mrg-scheduler-kit [data-slot="scheduler-agenda"] li button[aria-pressed="true"] {
      border-color: Highlight;
      color: HighlightText;
      background: Highlight;
    }
  }
}

"use client";

import "./scheduler-kit.css";

import {
  forwardRef,
  useId,
  useMemo,
  useState,
  type FormEvent,
  type HTMLAttributes,
  type ReactNode,
} from "react";

import { Button } from "../../components/button/button";
import { Calendar } from "../../components/calendar/calendar";
import {
  type SchedulerAdapter,
  type SchedulerEvent,
  type SchedulerSnapshot,
} from "./scheduler-kit-adapter";
import { useScheduler } from "./scheduler-kit-state";

const FIXTURE_EPOCH_DATE = "1970-01-01";

export type SchedulerView = "agenda" | "calendar";

export interface SchedulerKitProps extends Omit<
  HTMLAttributes<HTMLDivElement>,
  "children" | "defaultValue" | "onChange"
> {
  /** Consumer scheduling adapter that owns storage, timezone resolution, and authorization. */
  readonly adapter: SchedulerAdapter;
  /** Adds polite mutation feedback; false removes the live region and change announcements. */
  readonly announceChanges?: boolean;
  /** Initial local date in `YYYY-MM-DD` form for uncontrolled selection. */
  readonly defaultSelectedDate?: string;
  /** Initial IANA timezone identifier for uncontrolled display and editing. */
  readonly defaultTimeZone?: string;
  /** Initial agenda or calendar presentation for uncontrolled view selection. */
  readonly defaultView?: SchedulerView;
  /** Initial calendar visibility filter for uncontrolled use. */
  readonly defaultVisibleCalendarIds?: readonly string[];
  /** Disables date, filter, view, edit, and mutation controls while preserving schedule context. */
  readonly disabled?: boolean;
  /** Optional server-provided snapshot that bypasses the initial adapter load. */
  readonly initialSnapshot?: SchedulerSnapshot;
  /** Accessible and visible workspace name, defaulting to `Scheduler`. */
  readonly label?: ReactNode;
  /** Prevents adapter requests and presents explicit offline recovery context. */
  readonly offline?: boolean;
  /** Reports controlled or uncontrolled selected-date changes. */
  readonly onSelectedDateChange?: (date: string) => void;
  /** Reports controlled or uncontrolled timezone changes. */
  readonly onTimeZoneChange?: (timeZone: string) => void;
  /** Reports controlled or uncontrolled agenda/calendar presentation changes. */
  readonly onViewChange?: (view: SchedulerView) => void;
  /** Reports controlled or uncontrolled calendar visibility filter changes. */
  readonly onVisibleCalendarIdsChange?: (ids: readonly string[]) => void;
  /** Prevents schedule mutations while retaining date, view, and event review. */
  readonly readOnly?: boolean;
  /** Controlled selected local date; omit `defaultSelectedDate` when supplied. */
  readonly selectedDate?: string;
  /** Adds conflict explanations and supported resolution actions; false removes that recovery UI. */
  readonly showConflictGuidance?: boolean;
  /** Adds a computed draft duration summary; false removes its output and calculation display. */
  readonly showDurationSummary?: boolean;
  /** Adds selected timezone context near schedule times; false removes that explanatory output. */
  readonly showTimeZoneContext?: boolean;
  /** Controlled selected IANA timezone identifier; omit `defaultTimeZone` when supplied. */
  readonly timeZone?: string;
  /** Non-empty unique IANA timezone choices offered by the workspace. */
  readonly timeZones?: readonly string[];
  /** Controlled agenda or calendar presentation; use with `onViewChange`. */
  readonly view?: SchedulerView;
  /** Controlled visible calendar identifiers; omit uncontrolled defaults when supplied. */
  readonly visibleCalendarIds?: readonly string[];
}

interface LocalParts {
  readonly date: string;
  readonly time: string;
}

function localParts(value: string, timeZone: string): LocalParts {
  const parts = new Intl.DateTimeFormat("en-CA", {
    day: "2-digit",
    hour: "2-digit",
    hour12: false,
    minute: "2-digit",
    month: "2-digit",
    timeZone,
    year: "numeric",
  }).formatToParts(new Date(value));
  const read = (type: Intl.DateTimeFormatPartTypes) =>
    parts.find((part) => part.type === type)?.value ?? "";
  return {
    date: `${read("year")}-${read("month")}-${read("day")}`,
    time: `${read("hour").replace("24", "00")}:${read("minute")}`,
  };
}

function formatEventTime(event: SchedulerEvent, timeZone: string): string {
  const formatter = new Intl.DateTimeFormat(undefined, {
    hour: "numeric",
    minute: "2-digit",
    timeZone,
    timeZoneName: "short",
  });
  return `${formatter.format(new Date(event.start))} – ${formatter.format(new Date(event.end))}`;
}

function durationMinutes(start: string, end: string): number | null {
  if (!/^\d{2}:\d{2}$/u.test(start) || !/^\d{2}:\d{2}$/u.test(end) || end <= start) return null;
  const toMinutes = (value: string) => Number(value.slice(0, 2)) * 60 + Number(value.slice(3));
  return toMinutes(end) - toMinutes(start);
}

export const SchedulerKit = forwardRef<HTMLDivElement, SchedulerKitProps>(function SchedulerKit(
  {
    adapter,
    announceChanges = false,
    className,
    defaultSelectedDate = FIXTURE_EPOCH_DATE,
    defaultTimeZone = "UTC",
    defaultView = "calendar",
    defaultVisibleCalendarIds,
    disabled = false,
    initialSnapshot,
    label = "Scheduler",
    offline = false,
    onSelectedDateChange,
    onTimeZoneChange,
    onViewChange,
    onVisibleCalendarIdsChange,
    readOnly = false,
    selectedDate,
    showConflictGuidance = false,
    showDurationSummary = false,
    showTimeZoneContext = false,
    timeZone,
    timeZones = ["UTC"],
    view,
    visibleCalendarIds,
    ...props
  },
  ref,
) {
  if (timeZones.length === 0 || new Set(timeZones).size !== timeZones.length) {
    throw new Error("Mergora SchedulerKit timeZones must be non-empty and unique.");
  }
  if (selectedDate !== undefined && defaultSelectedDate !== FIXTURE_EPOCH_DATE) {
    throw new Error(
      "Mergora SchedulerKit controlled date cannot be combined with defaultSelectedDate.",
    );
  }
  if (timeZone !== undefined && defaultTimeZone !== "UTC") {
    throw new Error(
      "Mergora SchedulerKit controlled timeZone cannot be combined with defaultTimeZone.",
    );
  }
  if (visibleCalendarIds !== undefined && defaultVisibleCalendarIds !== undefined) {
    throw new Error(
      "Mergora SchedulerKit controlled calendar filters cannot be combined with defaults.",
    );
  }
  const scheduler = useScheduler({
    adapter,
    ...(initialSnapshot === undefined ? {} : { initialSnapshot }),
    offline,
  });
  const generatedId = useId().replaceAll(":", "");
  const [localDate, setLocalDate] = useState(defaultSelectedDate);
  const [localTimeZone, setLocalTimeZone] = useState(defaultTimeZone);
  const [localView, setLocalView] = useState(defaultView);
  const [localVisibleIds, setLocalVisibleIds] = useState<readonly string[] | null>(
    defaultVisibleCalendarIds ?? null,
  );
  const [editingId, setEditingId] = useState<string | null>(null);
  const [draftTimes, setDraftTimes] = useState({ end: "10:00", start: "09:00" });
  const resolvedDate = selectedDate ?? localDate;
  const resolvedTimeZone = timeZone ?? localTimeZone;
  const resolvedView = view ?? localView;
  const allCalendarIds = scheduler.snapshot?.calendars.map((calendar) => calendar.id) ?? [];
  const resolvedVisibleIds = visibleCalendarIds ?? localVisibleIds ?? allCalendarIds;
  const visibleSet = useMemo(() => new Set(resolvedVisibleIds), [resolvedVisibleIds]);
  const visibleEvents = useMemo(
    () =>
      (scheduler.snapshot?.events ?? [])
        .filter(
          (event) =>
            visibleSet.has(event.calendarId) &&
            localParts(event.start, resolvedTimeZone).date === resolvedDate,
        )
        .sort((left, right) => left.start.localeCompare(right.start)),
    [resolvedDate, resolvedTimeZone, scheduler.snapshot?.events, visibleSet],
  );
  const editingEvent = scheduler.snapshot?.events.find((event) => event.id === editingId);
  const duration = durationMinutes(draftTimes.start, draftTimes.end);
  const busy = scheduler.mutationState === "pending";

  const setDate = (next: string): void => {
    if (disabled) return;
    if (selectedDate === undefined) setLocalDate(next);
    onSelectedDateChange?.(next);
  };
  const setZone = (next: string): void => {
    if (disabled) return;
    if (timeZone === undefined) setLocalTimeZone(next);
    onTimeZoneChange?.(next);
  };
  const setPresentation = (next: SchedulerView): void => {
    if (disabled) return;
    if (view === undefined) setLocalView(next);
    onViewChange?.(next);
  };
  const toggleCalendar = (id: string): void => {
    if (disabled) return;
    const next = visibleSet.has(id)
      ? resolvedVisibleIds.filter((candidate) => candidate !== id)
      : [...resolvedVisibleIds, id];
    if (visibleCalendarIds === undefined) setLocalVisibleIds(next);
    onVisibleCalendarIdsChange?.(next);
  };

  if (scheduler.snapshot === null) {
    return (
      <div
        {...props}
        aria-busy={scheduler.state === "loading" || undefined}
        className={className === undefined ? "mrg-scheduler-kit" : `mrg-scheduler-kit ${className}`}
        data-maturity="beta"
        data-slot="scheduler-kit"
        ref={ref}
      >
        <h1>{label}</h1>
        {scheduler.state === "loading" ? <p role="status">Loading schedule...</p> : null}
        {scheduler.state === "offline" ? (
          <div role="alert">The schedule is unavailable while offline.</div>
        ) : null}
        {scheduler.state === "error" ? (
          <div role="alert">
            <p>{scheduler.error}</p>
            <Button onClick={() => void scheduler.reload()} variant="secondary">
              Retry loading
            </Button>
          </div>
        ) : null}
      </div>
    );
  }

  const draftEventParts =
    editingEvent === undefined ? null : localParts(editingEvent.start, resolvedTimeZone);
  const draftEventEnd =
    editingEvent === undefined ? null : localParts(editingEvent.end, resolvedTimeZone);

  return (
    <div
      {...props}
      aria-busy={busy || undefined}
      className={className === undefined ? "mrg-scheduler-kit" : `mrg-scheduler-kit ${className}`}
      data-maturity="beta"
      data-offline={scheduler.state === "offline" || undefined}
      data-slot="scheduler-kit"
      ref={ref}
    >
      <header data-slot="scheduler-header">
        <div>
          <span data-slot="scheduler-maturity">Beta</span>
          <h1>{label}</h1>
          <p>Calendar and agenda views share one explicit time-zone boundary.</p>
        </div>
        <div aria-label="Schedule presentation" data-slot="scheduler-view" role="group">
          <Button
            aria-pressed={resolvedView === "calendar"}
            disabled={disabled}
            onClick={() => setPresentation("calendar")}
            variant="secondary"
          >
            Calendar
          </Button>
          <Button
            aria-pressed={resolvedView === "agenda"}
            disabled={disabled}
            onClick={() => setPresentation("agenda")}
            variant="secondary"
          >
            Agenda
          </Button>
        </div>
      </header>

      {scheduler.state === "offline" ? (
        <div data-slot="scheduler-offline" role="alert">
          Offline: cached events remain visible; editing is unavailable.
        </div>
      ) : null}
      {scheduler.mutationState === "error" ? (
        <div data-slot="scheduler-error" role="alert">
          {scheduler.mutationError}
        </div>
      ) : null}

      <aside data-slot="scheduler-filters">
        <fieldset>
          <legend>Calendars</legend>
          {scheduler.snapshot.calendars.map((calendar) => (
            <label key={calendar.id}>
              <input
                checked={visibleSet.has(calendar.id)}
                disabled={disabled}
                onChange={() => toggleCalendar(calendar.id)}
                type="checkbox"
              />
              <span aria-hidden="true" data-slot="scheduler-calendar-mark" />
              {calendar.label}
            </label>
          ))}
        </fieldset>
        <label htmlFor={`${generatedId}-timezone`}>Time zone</label>
        <select
          disabled={disabled}
          id={`${generatedId}-timezone`}
          onChange={(event) => setZone(event.currentTarget.value)}
          value={resolvedTimeZone}
        >
          {timeZones.map((zone) => (
            <option key={zone} value={zone}>
              {zone}
            </option>
          ))}
        </select>
        {showTimeZoneContext ? (
          <aside data-slot="scheduler-timezone-context">
            <strong>Time-zone context</strong>
            <p>
              Times are shown in {resolvedTimeZone}. The adapter owns conversion from wall time to
              an instant.
            </p>
          </aside>
        ) : null}
      </aside>

      <main data-slot="scheduler-main" data-view={resolvedView}>
        <section data-slot="scheduler-calendar-panel">
          <Calendar
            aria-label="Event date"
            disabled={disabled}
            inputLabel="Selected schedule date"
            onValueChange={setDate}
            readOnly={readOnly}
            value={resolvedDate}
          />
        </section>
        <section aria-labelledby={`${generatedId}-agenda`} data-slot="scheduler-agenda">
          <div data-slot="scheduler-section-heading">
            <div>
              <h2 id={`${generatedId}-agenda`}>Agenda</h2>
              <p>{resolvedDate}</p>
            </div>
            <Button
              disabled={disabled || readOnly || offline}
              onClick={() => setEditingId(null)}
              variant="secondary"
            >
              New event
            </Button>
          </div>
          {visibleEvents.length === 0 ? (
            <div data-slot="scheduler-empty">
              <h3>No events on this date</h3>
              <p>Adjust calendar filters or create an event.</p>
            </div>
          ) : (
            <ol>
              {visibleEvents.map((event) => (
                <li key={event.id}>
                  <button
                    aria-pressed={editingId === event.id}
                    disabled={disabled}
                    onClick={() => {
                      const start = localParts(event.start, resolvedTimeZone);
                      const end = localParts(event.end, resolvedTimeZone);
                      setDraftTimes({ end: end.time, start: start.time });
                      setEditingId(event.id);
                    }}
                    type="button"
                  >
                    <span aria-hidden="true" data-slot="scheduler-event-mark" />
                    <span>
                      <strong>{event.title}</strong>
                      <span>{formatEventTime(event, resolvedTimeZone)}</span>
                      {event.location === undefined ? null : <span>{event.location}</span>}
                    </span>
                  </button>
                </li>
              ))}
            </ol>
          )}
        </section>

        <section aria-labelledby={`${generatedId}-editor`} data-slot="scheduler-editor">
          <h2 id={`${generatedId}-editor`}>
            {editingEvent === undefined ? "Create event" : "Edit event"}
          </h2>
          <form
            key={editingEvent?.id ?? "new"}
            onReset={(event) => {
              if (readOnly) {
                event.preventDefault();
                return;
              }
              setEditingId(null);
              setDraftTimes({ end: "10:00", start: "09:00" });
            }}
            onSubmit={(event: FormEvent<HTMLFormElement>) => {
              event.preventDefault();
              const data = new FormData(event.currentTarget);
              const title = data.get("title");
              const date = data.get("date");
              const startTime = data.get("startTime");
              const endTime = data.get("endTime");
              const calendarId = data.get("calendarId");
              const location = data.get("location");
              const description = data.get("description");
              if (
                typeof title !== "string" ||
                typeof date !== "string" ||
                typeof startTime !== "string" ||
                typeof endTime !== "string" ||
                typeof calendarId !== "string"
              )
                return;
              void scheduler
                .save({
                  calendarId,
                  date,
                  ...(typeof description === "string" && description.trim() !== ""
                    ? { description }
                    : {}),
                  endTime,
                  ...(editingEvent === undefined ? {} : { id: editingEvent.id }),
                  ...(typeof location === "string" && location.trim() !== "" ? { location } : {}),
                  startTime,
                  timeZone: resolvedTimeZone,
                  title,
                })
                .then((saved) => {
                  if (saved) setEditingId(null);
                });
            }}
          >
            <label htmlFor={`${generatedId}-title`}>Title</label>
            <input
              defaultValue={editingEvent?.title ?? ""}
              disabled={disabled}
              id={`${generatedId}-title`}
              maxLength={160}
              name="title"
              readOnly={readOnly}
              required
            />
            <label htmlFor={`${generatedId}-date`}>Date</label>
            <input
              defaultValue={draftEventParts?.date ?? resolvedDate}
              disabled={disabled}
              id={`${generatedId}-date`}
              name="date"
              readOnly={readOnly}
              required
              type="date"
            />
            <div data-slot="scheduler-time-fields">
              <label>
                Start
                <input
                  defaultValue={draftEventParts?.time ?? draftTimes.start}
                  disabled={disabled}
                  name="startTime"
                  onChange={(event) =>
                    setDraftTimes((current) => ({ ...current, start: event.currentTarget.value }))
                  }
                  readOnly={readOnly}
                  required
                  type="time"
                />
              </label>
              <label>
                End
                <input
                  defaultValue={draftEventEnd?.time ?? draftTimes.end}
                  disabled={disabled}
                  name="endTime"
                  onChange={(event) =>
                    setDraftTimes((current) => ({ ...current, end: event.currentTarget.value }))
                  }
                  readOnly={readOnly}
                  required
                  type="time"
                />
              </label>
            </div>
            {showDurationSummary ? (
              <output data-slot="scheduler-duration">
                {duration === null ? "Choose an end time after the start." : `${duration} minutes`}
              </output>
            ) : null}
            <label htmlFor={`${generatedId}-calendar`}>Calendar</label>
            <select
              defaultValue={editingEvent?.calendarId ?? scheduler.snapshot.calendars[0]?.id}
              disabled={disabled || readOnly}
              id={`${generatedId}-calendar`}
              name="calendarId"
              required
            >
              {scheduler.snapshot.calendars.map((calendar) => (
                <option key={calendar.id} value={calendar.id}>
                  {calendar.label}
                </option>
              ))}
            </select>
            <label htmlFor={`${generatedId}-location`}>Location (optional)</label>
            <input
              defaultValue={editingEvent?.location ?? ""}
              disabled={disabled}
              id={`${generatedId}-location`}
              name="location"
              readOnly={readOnly}
            />
            <label htmlFor={`${generatedId}-description`}>Description (optional)</label>
            <textarea
              defaultValue={editingEvent?.description ?? ""}
              disabled={disabled}
              id={`${generatedId}-description`}
              name="description"
              readOnly={readOnly}
              rows={3}
            />
            <div data-slot="scheduler-actions">
              <Button
                disabled={disabled || readOnly || offline || duration === null}
                pending={busy}
                pendingLabel="Saving event"
                type="submit"
              >
                Save event
              </Button>
              <Button disabled={disabled || readOnly || busy} type="reset" variant="quiet">
                Reset
              </Button>
              {editingEvent !== undefined && adapter.remove !== undefined ? (
                <Button
                  disabled={disabled || readOnly || offline}
                  onClick={() =>
                    void scheduler.remove(editingEvent.id).then(() => setEditingId(null))
                  }
                  type="button"
                  variant="destructive"
                >
                  Remove event
                </Button>
              ) : null}
            </div>
          </form>
        </section>

        {showConflictGuidance && scheduler.snapshot.conflicts.length > 0 ? (
          <section aria-labelledby={`${generatedId}-conflicts`} data-slot="scheduler-conflicts">
            <h2 id={`${generatedId}-conflicts`}>Schedule conflicts</h2>
            {scheduler.snapshot.conflicts.map((conflict) => (
              <article key={conflict.id}>
                <p>{conflict.summary}</p>
                {adapter.resolveConflict === undefined ? null : (
                  <div data-slot="scheduler-actions">
                    <Button
                      disabled={disabled || readOnly || offline}
                      onClick={() => void scheduler.resolveConflict(conflict.id, "keep-existing")}
                      variant="secondary"
                    >
                      Keep existing event
                    </Button>
                    <Button
                      disabled={disabled || readOnly || offline}
                      onClick={() => void scheduler.resolveConflict(conflict.id, "save-anyway")}
                      variant="secondary"
                    >
                      Keep both events
                    </Button>
                  </div>
                )}
              </article>
            ))}
          </section>
        ) : null}
        {announceChanges ? (
          <output aria-live="polite" data-slot="scheduler-announcer">
            {scheduler.mutationState === "pending"
              ? "Schedule change in progress."
              : scheduler.mutationState === "success"
                ? "Schedule updated."
                : ""}
          </output>
        ) : null}
      </main>
    </div>
  );
});

SchedulerKit.displayName = "SchedulerKit";
export const SchedulerKitPage = SchedulerKit;
